import{c as a,Q as t,j as r,m as n}from"./chunks/framework.BXc4yaFE.js";const u=JSON.parse('{"title":"Latent Space — 2026-04-24","description":"","frontmatter":{"title":"Latent Space — 2026-04-24","date":"2026-04-24T00:00:00.000Z","source":"Latent Space","type":"ai-news"},"headers":[],"relativePath":"research/ai-news/2026-04/2026-04-24-latent-space.md","filePath":"research/ai-news/2026-04/2026-04-24-latent-space.md","lastUpdated":1779894392000}'),s={name:"research/ai-news/2026-04/2026-04-24-latent-space.md"};function o(i,e,l,p,c,h){return t(),r("div",null,[...e[0]||(e[0]=[n('<h1 id="🔬-latent-space-—-2026-04-24" tabindex="-1">🔬 Latent Space — 2026-04-24 <a class="header-anchor" href="#🔬-latent-space-—-2026-04-24" aria-label="Permalink to &quot;🔬 Latent Space — 2026-04-24&quot;">​</a></h1><blockquote><p>swyx 開發者簡報，未公開專案 + 工程視角 來源：<a href="https://www.latent.space/feed" target="_blank" rel="noreferrer">Latent Space</a></p></blockquote><hr><h2 id="ainews-gpt-5-5-and-openai-codex-superapp" tabindex="-1"><a href="https://www.latent.space/p/ainews-gpt-55-and-openai-codex-superapp" target="_blank" rel="noreferrer">[AINews] GPT 5.5 and OpenAI Codex Superapp</a> <a class="header-anchor" href="#ainews-gpt-5-5-and-openai-codex-superapp" aria-label="Permalink to &quot;[[AINews] GPT 5.5 and OpenAI Codex Superapp](https://www.latent.space/p/ainews-gpt-55-and-openai-codex-superapp)&quot;">​</a></h2><p><em>🔬 Latent Space | 2026-04-24</em></p><p>A week after <a href="https://www.latent.space/p/ainews-anthropic-claude-opus-47-literally" target="_blank" rel="noreferrer">Opus 4.7</a>, it was OpenAI’s turn to fire back with very similar Pareto frontier improvement charts for <a href="https://openai.com/index/introducing-gpt-5-5/" target="_blank" rel="noreferrer">GPT 5.5</a> (as <a href="https://x.com/polynoamial/status/2047387675762802998?s=46" target="_blank" rel="noreferrer">Noam Brown prefers</a> — raw 1 dimensional intelligence measures are giving way to 2D intelligence per dollar charts). In the 4.7 vs 5.5 bakeoff, you have to read between the lines to see what was NOT mentioned (<a href="https://x.com/chowdhuryneil/status/2047416077622395025?s=46" target="_blank" rel="noreferrer">coding</a>), but in terms of overall intelligence, AA crowns this the top independently validated model in the world, AND…</p><p><a href="https://x.com/ArtificialAnlys/status/2047378419282034920" target="_blank" rel="noreferrer">AA chart</a></p><p>… intelligence per dollar (“GPT-5.5 (medium) scores the same as Claude Opus 4.7 (max) on our Intelligence Index at one quarter of the cost (~$1,200 vs $4,800) - although Gemini 3.1 Pro Preview scores the same at a cost of ~$900.”</p><p><a href="https://x.com/scaling01/status/2047380890402123928?s=20" target="_blank" rel="noreferrer">aa 2D </a></p><p>There are <a href="https://x.com/scaling01/status/2047425178724921618?s=46" target="_blank" rel="noreferrer">some training hardware tidbits</a> and <a href="https://x.com/tszzl/status/2047386955550470245?s=46" target="_blank" rel="noreferrer">positive</a> <a href="https://x.com/aidan_mclau/status/2047388367705575701?s=46" target="_blank" rel="noreferrer">RSI</a> vibes and <a href="https://x.com/clad3815/status/2047392779006013833?s=12" target="_blank" rel="noreferrer">cool</a> <a href="https://x.com/andonlabs/status/2047377260412649967?s=46" target="_blank" rel="noreferrer">alternative</a> <a href="https://x.com/sebastienbubeck/status/2047383628922167390?s=46" target="_blank" rel="noreferrer">benchmarks</a>.</p><p>But if you just treated today as a mere point update model launch (<a href="https://x.com/davis7/status/2047414463595528467" target="_blank" rel="noreferrer">some would prefer to call it 5.9</a>), you’d be mistaken - it’s also <a href="https://x.com/sama/status/2047378431260664058?s=20" target="_blank" rel="noreferrer">bundling </a>a big Codex launch day:</p><p><a href="https://x.com/thsottiaux/status/2047387017974337611?s=46" target="_blank" rel="noreferrer">twitter</a></p><p>With built in browser control and the other features in <a href="https://x.com/ajambrosino/status/2047381565534322694?s=20" target="_blank" rel="noreferrer">this mega-update</a>, as well as folding in the now defunct <a href="https://www.youtube.com/watch?v=W2cBTVr8nxU&amp;pp=2AYl0gcJCZEKAYcqIYzv" target="_blank" rel="noreferrer">Prism</a> (RIP), OpenAI seems to have made the critical and retoractively obvious choice to turn Codex into the <a href="https://www.wsj.com/tech/openai-plans-launch-of-desktop-superapp-to-refocus-simplify-user-experience-9e19931d" target="_blank" rel="noreferrer">base of its superapp strategy</a>.</p><p>AI News for 4/22/2026-4/23/2026. We checked 12 subreddits, <a href="https://twitter.com/i/lists/1585430245762441216" target="_blank" rel="noreferrer">544 Twitters</a> and no further Discords. <a href="https://news.smol.ai/" target="_blank" rel="noreferrer">AINews’ website</a> lets you search all past issues. As a reminder, <a href="https://www.latent.space/p/2026" target="_blank" rel="noreferrer">AINews is now a section of Latent Space</a>. You can <a href="https://support.substack.com/hc/en-us/articles/8914938285204-How-do-I-subscribe-to-or-unsubscribe-from-a-section-on-Substack" target="_blank" rel="noreferrer">opt in/out</a> of email frequencies!</p><p>AI Twitter Recap</p><p>OpenAI’s GPT-5.5 launch: stronger agentic coding, broader computer use, and a push on token-efficiency</p><p>GPT-5.5 is the day’s dominant release: OpenAI launched <a href="https://x.com/OpenAI/status/2047376561205325845" target="_blank" rel="noreferrer">GPT-5.5</a>, positioned as “a new class of intelligence for real work,” with rollout across <a href="https://x.com/OpenAI/status/2047376568809636017" target="_blank" rel="noreferrer">ChatGPT and Codex</a> and API access delayed pending additional safeguards. OpenAI and community benchmark posts converged on a profile of better long-horizon execution, stronger computer-use behavior, and materially improved token efficiency rather than a pure across-the-board benchmark blowout. Reported numbers include 82.7% Terminal-Bench 2.0, 58.6% SWE-Bench Pro, 84.9% GDPval, 78.7% OSWorld-Verified, 81.8% CyberGym, 84.4% BrowseComp, and 51.7% FrontierMath Tier 1–3 via <a href="https://x.com/reach_vb/status/2047377562339524659" target="_blank" rel="noreferrer">@reach_vb</a>, with Artificial Analysis saying GPT-5.5 now leads or ties several headline evals and sits on a new cost/performance frontier despite higher per-token pricing <a href="https://x.com/ArtificialAnlys/status/2047378419282034920" target="_blank" rel="noreferrer">@ArtificialAnlys</a>, <a href="https://x.com/scaling01/status/2047380890402123928" target="_blank" rel="noreferrer">@scaling01</a>. OpenAI also emphasized that in ChatGPT, stack-level inference gains made GPT-5.5 Pro more practical for demanding tasks <a href="https://x.com/OpenAI/status/2047376567559668222" target="_blank" rel="noreferrer">@OpenAI</a>.</p><p>Pricing, context, infra, and practical behavior: API pricing was reported at $5/$30 per 1M input/output tokens for GPT-5.5 and $30/$180 for Pro <a href="https://x.com/scaling01/status/2047375819144597737" target="_blank" rel="noreferrer">@scaling01</a>, with <a href="https://x.com/sama/status/2047379036419014928" target="_blank" rel="noreferrer">Sam Altman noting</a> a 1M context window in API and lower token use per task than 5.4. Multiple early users described the model as more “human,” less formal, and better suited to persistent agent workflows than prior GPTs, especially inside Codex <a href="https://x.com/MatthewBerman/status/2047375703516361174" target="_blank" rel="noreferrer">@MatthewBerman</a>, <a href="https://x.com/danshipper/status/2047375686688473134" target="_blank" rel="noreferrer">@danshipper</a>, <a href="https://x.com/omarsar0/status/2047424707310289058" target="_blank" rel="noreferrer">@omarsar0</a>. OpenAI claimed the model was co-designed for NVIDIA GB200/300 systems and that the model itself helped improve its own inference stack <a href="https://x.com/scaling01/status/2047377992016384068" target="_blank" rel="noreferrer">@scaling01</a>, while <a href="https://x.com/sama/status/2047386068194852963" target="_blank" rel="noreferrer">@sama</a> framed the company increasingly as an AI inference company. A recurrent theme from users: GPT-5.5 often feels like a step-function upgrade in autonomy, but can also be exploratory and require tighter instruction to stay on track <a href="https://x.com/theo/status/2047379702189310085" target="_blank" rel="noreferrer">@theo</a>.</p><p>Codex becomes a fuller agent workspace: In parallel, OpenAI shipped substantial Codex upgrades: browser control, Sheets/Slides, Docs/PDFs, OS-wide dictation, and auto-review mode <a href="https://x.com/ajambrosino/status/2047381565534322694" target="_blank" rel="noreferrer">@ajambrosino</a>. OpenAI says Codex can now interact with web apps, click through flows, capture screenshots, and iterate until task completion <a href="https://x.com/OpenAIDevs/status/2047381283358355706" target="_blank" rel="noreferrer">@OpenAIDevs</a>, while Auto-review uses a secondary “guardian” agent to reduce approvals on longer runs <a href="https://x.com/OpenAIDevs/status/2047436655863464011" target="_blank" rel="noreferrer">@OpenAIDevs</a>, <a href="https://x.com/gdb/status/2047489218998628780" target="_blank" rel="noreferrer">@gdb</a>. User reports suggest this is expanding Codex from a coding tool into a broader computer-work agent, spanning QA, spreadsheets, presentations, app building, research loops, and overnight experimental runs <a href="https://x.com/gdb/status/2047387783111868707" target="_blank" rel="noreferrer">@gdb</a>, <a href="https://x.com/tszzl/status/2047386955550470245" target="_blank" rel="noreferrer">@tszzl</a>, <a href="https://x.com/aidan_mclau/status/2047388367705575701" target="_blank" rel="noreferrer">@aidan_mclau</a>.</p><p>DeepSeek-V4 Preview: 1.6T MIT-licensed open model, 1M context, and aggressive pricing</p><p>DeepSeek answered GPT-5.5 within hours: DeepSeek released <a href="https://x.com/deepseek_ai/status/2047516922263285776" target="_blank" rel="noreferrer">DeepSeek-V4 Preview</a>, open-sourcing V4-Pro and V4-Flash under an MIT license. The headline specs are unusually aggressive: V4-Pro: 1.6T total params / 49B active, V4-Flash: 284B / 13B active, both with 1M token context and support for thinking/non-thinking modes <a href="https://x.com/deepseek_ai/status/2047516945466188072" target="_blank" rel="noreferrer">@deepseek_ai</a>, <a href="https://x.com/Yuchenj_UW/status/2047514092756418757" target="_blank" rel="noreferrer">@Yuchenj_UW</a>. Community reactions quickly framed it as the new open-model flagship, competitive with top closed models from the prior generation and a major leap over DeepSeek V3.x <a href="https://x.com/arena/status/2047518354903359697" target="_blank" rel="noreferrer">@arena</a>, <a href="https://x.com/scaling01/status/2047512176856899985" target="_blank" rel="noreferrer">@scaling01</a>, <a href="https://x.com/kimmonismus/status/2047514623356579869" target="_blank" rel="noreferrer">@kimmonismus</a>.</p><p>Technical report highlights: long-context efficiency, hybrid attention, and Muon: The launch was notable not just for weights but for a same-day tech report <a href="https://x.com/scaling01/status/2047510520618516572" target="_blank" rel="noreferrer">@scaling01</a>. Community summaries point to two new compressed/hybrid attention mechanisms, mHC, Muon-based training, FP4 quantization-aware training, and pretraining on roughly 32T tokens <a href="https://x.com/scaling01/status/2047510190044409860" target="_blank" rel="noreferrer">@scaling01</a>, <a href="https://x.com/iScienceLuvr/status/2047514399393579235" target="_blank" rel="noreferrer">@iScienceLuvr</a>, <a href="https://x.com/eliebakouch/status/2047519300399837677" target="_blank" rel="noreferrer">@eliebakouch</a>. The strongest technical discussion centered on making 1M context practical, with reported ~4x compute efficiency improvements and order-of-magnitude KV-cache reductions relative to earlier DeepSeek-style stacks <a href="https://x.com/Hangsiin/status/2047523724929405328" target="_blank" rel="noreferrer">@Hangsiin</a>. The rapid infra response was also notable: vLLM announced <a href="https://x.com/vllm_project/status/2047520252851105796" target="_blank" rel="noreferrer">day-0 support</a> and detailed how it implemented the new attention stack; SGLang shipped <a href="https://x.com/lmsysorg/status/2047511629919932623" target="_blank" rel="noreferrer">day-0 optimizations and RL pipeline support</a>.</p><p>Pricing may be as important as the model: DeepSeek’s posted pricing is exceptionally aggressive: V4-Flash at $0.14/$0.28 and V4-Pro at $1.74/$3.48 per 1M input/output tokens <a href="https://x.com/scaling01/status/2047508350238175526" target="_blank" rel="noreferrer">@scaling01</a>, <a href="https://x.com/teortaxesTex/status/2047508587883250112" target="_blank" rel="noreferrer">@teortaxesTex</a>. Several commenters highlighted Flash as potentially the more disruptive SKU if serving quality holds, given the combination of very low cost, 1M context, and open weights <a href="https://x.com/Hangsiin/status/2047515855949623667" target="_blank" rel="noreferrer">@Hangsiin</a>, <a href="https://x.com/arena/status/2047524055679729885" target="_blank" rel="noreferrer">@arena</a>. The main caveat from DeepSeek: V4-Pro throughput is currently limited by high-end compute constraints, with the company explicitly pointing to future Ascend 950 availability for price drops <a href="https://x.com/teortaxesTex/status/2047523707199909977" target="_blank" rel="noreferrer">@teortaxesTex</a>.</p><p>Agent infrastructure and tooling: memory, orchestration, browsers, and enterprise plumbing</p><p>Agents are becoming systems problems, not just model problems: Several posts emphasized that production agent work is increasingly about harnesses, evals, memory, and orchestration. A useful example was the writeup on stateless decision memory for enterprise agents, which replaces mutable per-agent state with immutable decision logs/event sourcing to improve horizontal scalability, auditability, and fault tolerance <a href="https://x.com/omarsar0/status/2047325132096758228" target="_blank" rel="noreferrer">@omarsar0</a>. In a similar vein, <a href="https://x.com/Vtrivedy10/status/2047362615836336473" target="_blank" rel="noreferrer">@Vtrivedy10</a> argued that trace data → evals/environments → harness engineering/SFT-RL is the core flywheel for improving production agents, and later used Anthropic’s Claude Code regression as a case study for why open harnesses and open evals matter <a href="https://x.com/Vtrivedy10/status/2047384831995371631" target="_blank" rel="noreferrer">@Vtrivedy10</a>.</p><p>New tooling around control surfaces: Cua open-sourced <a href="https://x.com/trycua/status/2047383200348221632" target="_blank" rel="noreferrer">Cua Driver</a>, a macOS driver for letting agents control arbitrary apps in the background with multi-player/multi-cursor support. Cognition published a post on <a href="https://x.com/cognition/status/2047392064355377194" target="_blank" rel="noreferrer">what it takes to build cloud agent infrastructure</a>, naming the practical stack: VM isolation, session persistence, environment provisioning, orchestration, and integrations. LangChain continued expanding LangSmith Fleet with file editing, webpage/presentation generation, and slash-command skills <a href="https://x.com/LangChain/status/2047362259983495215" target="_blank" rel="noreferrer">@LangChain</a>, while multiple users highlighted Fleet’s presentation renderer/viewer as a surprisingly useful agent-native artifact format <a href="https://x.com/BraceSproul/status/2047417882423022034" target="_blank" rel="noreferrer">@BraceSproul</a>.</p><p>Multi-agent orchestration is moving into products: Sakana AI launched the beta of Fugu, a multi-agent orchestration API that dynamically selects and coordinates frontier models, with claims of SOTA on SWE-Pro, GPQA-D, and ALE-Bench and even recursive test-time scaling via self-invocation <a href="https://x.com/SakanaAILabs/status/2047479445209145785" target="_blank" rel="noreferrer">@SakanaAILabs</a>, <a href="https://x.com/hardmaru/status/2047483783323283941" target="_blank" rel="noreferrer">@hardmaru</a>. Hermes Agent shipped <a href="https://x.com/Teknium/status/2047506967909015907" target="_blank" rel="noreferrer">v0.11.0</a> with a large contributor release, expanded providers, image generation support, and effectively immediate GPT-5.5 support <a href="https://x.com/Teknium/status/2047419336537846193" target="_blank" rel="noreferrer">@Teknium</a>. The direction is consistent: agents are becoming orchestration layers over heterogeneous tools and models, not single-model loops.</p><p>Vision, video, and multimodal systems: Vision Banana, Sapiens2, HDR video, and omni models</p><p>Google DeepMind’s Vision Banana reframes CV as generation: One of the more technically interesting research launches was <a href="https://x.com/songyoupeng/status/2047312019976785944" target="_blank" rel="noreferrer">Vision Banana</a>, a unified vision model that treats 2D/3D vision tasks as image generation, reportedly outperforming specialist SOTA systems across multiple vision tasks. The reaction from computer-vision researchers was that it signals a broader shift in how segmentation, depth, normals, and related tasks may be approached going forward <a href="https://x.com/sainingxie/status/2047339789926429166" target="_blank" rel="noreferrer">@sainingxie</a>. On the open side, Meta also released Sapiens2, a set of high-resolution vision transformers trained on 1B human images for human-centric perception tasks <a href="https://x.com/HuggingPapers/status/2047410529010844044" target="_blank" rel="noreferrer">@HuggingPapers</a>.</p><p>Video stack updates are moving past raw resolution into production formats: Kling’s “native 4K” rollout spread across multiple platforms, but the technically more novel launch may be LTX HDR beta, which argues the real bottleneck for AI video in production has been dynamic range, not just resolution, by moving beyond 8-bit SDR toward footage that can survive grading and compositing <a href="https://x.com/ltx_model/status/2047333864587018703" target="_blank" rel="noreferrer">@ltx_model</a>. That’s a more substantive improvement than the usual “4K” marketing alone. Separately, World Labs launched World Jam around Marble 1.1 + Spark LoD for interactive 3D creation <a href="https://x.com/theworldlabs/status/2047373234174304473" target="_blank" rel="noreferrer">@theworldlabs</a>.</p><p>Broader multimodal trend: unified models with explicit cross-modal reasoning: The newly shared Context Unrolling in Omni Models proposes a unified model trained across text, images, video, 3D geometry, and hidden representations, explicitly unrolling reasoning across modalities before producing outputs <a href="https://x.com/arankomatsuzaki/status/2047519009004716097" target="_blank" rel="noreferrer">@arankomatsuzaki</a>. Together with Vision Banana, this points to a recurring motif: fold disparate perception/generation tasks into fewer general multimodal backbones, then let inference-time reasoning bridge modalities.</p><p>Training, scaling, and research methods: globally distributed pretraining, self-play, and long-context internals</p><p>Google’s Decoupled DiLoCo tackles resilient global pretraining: Google DeepMind and Google Research introduced <a href="https://x.com/Ar_Douillard/status/2047329942547968171" target="_blank" rel="noreferrer">Decoupled DiLoCo</a>, which decouples distributed low-communication training to enable worldwide datacenter training, heterogeneous hardware, and tolerance to hardware failures without halting the job. This is a meaningful systems result because it targets a real frontier training bottleneck: keeping giant training runs alive and efficient across faulty, geographically distributed infrastructure, rather than assuming clean homogeneous clusters.</p><p>Algorithmic scaling beyond brute-force sampling: A self-play paper highlighted by <a href="https://x.com/LukeBailey181/status/2047340293490724945" target="_blank" rel="noreferrer">@LukeBailey181</a> studies why long-run self-play plateaus for LLMs and proposes an algorithm that lets a 7B model solve as many problems as pass@4 of a model 100x larger. Another recurring theme was token/computation efficiency as the real frontier metric; several posts argued that single-number intelligence comparisons are increasingly obsolete in a world where effort level and inference budget materially reshape capability <a href="https://x.com/polynoamial/status/2047387675762802998" target="_blank" rel="noreferrer">@polynoamial</a>. Relatedly, a thread on Neural Garbage Collection described training models to manage their own KV cache via RL rather than fixed heuristics, a potentially important direction for long-horizon agents <a href="https://x.com/cwolferesearch/status/2047476297031631102" target="_blank" rel="noreferrer">@cwolferesearch</a>.</p><p>Infra adoption signals: Together AI reported growth from 30B to 300T tokens/month YoY <a href="https://x.com/vipulved/status/2047183589222273231" target="_blank" rel="noreferrer">@vipulved</a>, a large-scale indicator of inference demand expansion. Epoch AI, meanwhile, revised down estimates for operational power at Stargate Abilene to ~0.3 GW currently and pushed the full 1.2 GW milestone to Q4 2026, underscoring continued uncertainty in tracking frontier compute deployment <a href="https://x.com/EpochAIResearch/status/2047442515608162481" target="_blank" rel="noreferrer">@EpochAIResearch</a>.</p><p>Top tweets (by engagement)</p><p>OpenAI GPT-5.5 launch: The highest-engagement technical post was OpenAI’s <a href="https://x.com/OpenAI/status/2047376561205325845" target="_blank" rel="noreferrer">GPT-5.5 announcement</a>, followed by <a href="https://x.com/sama/status/2047378253313106112" target="_blank" rel="noreferrer">@sama’s launch post</a> and OpenAI DevRel’s framing of GPT-5.5 as its smartest frontier model yet <a href="https://x.com/OpenAIDevs/status/2047377079352877534" target="_blank" rel="noreferrer">@OpenAIDevs</a>.</p><p>Claude Code regression post-mortem: Anthropic’s acknowledgment that <a href="https://x.com/ClaudeDevs/status/2047371123185287223" target="_blank" rel="noreferrer">Claude Code quality had slipped due to three issues and was fixed in v2.1.116+</a> was one of the most engaged engineering-product posts of the day, and sparked substantial discussion about harness sensitivity and regression testing.</p><p>DeepSeek-V4 Preview release: DeepSeek’s <a href="https://x.com/deepseek_ai/status/2047516922263285776" target="_blank" rel="noreferrer">official V4 Preview launch</a> quickly became the other major high-engagement technical event, especially given the combination of MIT license, 1M context, and aggressive pricing.</p><p>Vision Banana: Google DeepMind’s <a href="https://x.com/songyoupeng/status/2047312019976785944" target="_blank" rel="noreferrer">Vision Banana announcement</a> was the standout pure-research vision post.</p><p>ML-Intern and autonomous research workflows: The Hugging Face-adjacent <a href="https://x.com/akseljoonas/status/2047332440025321796" target="_blank" rel="noreferrer">ml-intern passing an internship-style test in 15 minutes</a> and subsequent reports of very high token consumption suggest strong interest in autonomous coding/research harnesses as distinct products, not just demos.</p><p>AI Reddit Recap</p><p>/r/LocalLlama + /r/localLLM Recap</p><p><a href="https://www.latent.space/p/ainews-gpt-55-and-openai-codex-superapp" target="_blank" rel="noreferrer"> Read more </a></p><hr>',45)])])}const m=a(s,[["render",o]]);export{u as __pageData,m as default};
